$ErrorActionPreference = "Stop"
$ProjectRoot = Split-Path -Parent $PSScriptRoot
$Utf8NoBom = New-Object System.Text.UTF8Encoding($false)

$RelativePath = "SQL\schema_v1.sql"
$FullPath = Join-Path $ProjectRoot $RelativePath
$Parent = Split-Path -Parent $FullPath
if (-not (Test-Path $Parent)) { New-Item -ItemType Directory -Force -Path $Parent | Out-Null }
$Content = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String("Cg=="))
[System.IO.File]::WriteAllText($FullPath, $Content, $Utf8NoBom)
Write-Host "Wrote $RelativePath"

$RelativePath = "Docs\Database\Database Schema.md"
$FullPath = Join-Path $ProjectRoot $RelativePath
$Parent = Split-Path -Parent $FullPath
if (-not (Test-Path $Parent)) { New-Item -ItemType Directory -Force -Path $Parent | Out-Null }
$Content = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText($FullPath, $Content, $Utf8NoBom)
Write-Host "Wrote $RelativePath"

Write-Host ""
Write-Host "Database schema files populated successfully."
Write-Host "Files written: 2"